// === src/App.js ===
import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import HomePage from './components/HomePage';
import PleadingsPage from './components/PleadingsPage';
import MotionsPage from './components/MotionsPage';
import FormsPage from './components/FormsPage';
import ResourcesPage from './components/ResourcesPage';
import ClientForm from './components/ClientForm';
import Login from './components/Login';
import { ThemeProvider } from './context/ThemeContext';
import { AuthProvider } from './context/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';

function App() {
  return (
    <AuthProvider>
      <ThemeProvider>
        <Router>
          <Routes>
            {/* Ruta pública */}
            <Route path="/login" element={<Login />} />

            {/* Ruta raíz - siempre redirige al login si no hay autenticación */}
            <Route 
              path="/" 
              element={<Navigate to="/login" replace />} 
            />

            {/* Todas las rutas protegidas */}
            <Route
              path="/*"
              element={
                <ProtectedRoute>
                  <Layout>
                    <Routes>
                      <Route path="/home" element={<HomePage />} />
                      <Route path="/pleadings" element={<PleadingsPage />} />
                      <Route path="/motions" element={<MotionsPage />} />
                      <Route path="/forms" element={<FormsPage />} />
                      <Route path="/resources/*" element={<ResourcesPage />} />
                      <Route path="/declaration/*" element={<DeclarationPage />} />
                    </Routes>
                  </Layout>
                </ProtectedRoute>
              }
            />
          </Routes>
        </Router>
      </ThemeProvider>
    </AuthProvider>
  );
}

export default App;
